import { Link, useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";
import { clearAuth, getAuth } from "../utils/auth";

export default function Navbar() {
  const navigate = useNavigate();
  const [auth, setAuthState] = useState(getAuth());

  // ✅ re-render navbar whenever login/logout happens
  useEffect(() => {
    const refresh = () => setAuthState(getAuth());
    window.addEventListener("auth-change", refresh);

    // also refresh if user changes localStorage manually
    window.addEventListener("storage", refresh);

    return () => {
      window.removeEventListener("auth-change", refresh);
      window.removeEventListener("storage", refresh);
    };
  }, []);

  const logout = () => {
    clearAuth();
    navigate("/login");
  };

  const isLogged = !!auth.token;
  const role = auth.role; // admin | manager | staff | client

  const navStyle = {
    padding: 12,
    background: "#222",
    color: "#fff",
    display: "flex",
    alignItems: "center",
    gap: 12,
  };

  const linkStyle = { color: "#fff", textDecoration: "none" };

  return (
    <nav style={navStyle}>
      {/* Public */}
      <Link to="/" style={linkStyle}>Home</Link>
      <Link to="/vehicles" style={linkStyle}>Vehicles</Link>

      {/* Right side push */}
      <div style={{ flex: 1 }} />

      {!isLogged && (
        <>
          <Link to="/login" style={linkStyle}>Login</Link>
          <Link to="/register" style={linkStyle}>Register</Link>
        </>
      )}

      {isLogged && role === "client" && (
        <>
          <Link to="/book-appointment" style={linkStyle}>Book Appointment</Link>
          <Link to="/my-appointments" style={linkStyle}>My Appointments</Link>
          <button onClick={logout} style={{ padding: "6px 10px", cursor: "pointer" }}>
            Logout
          </button>
        </>
      )}

      {isLogged && (role === "staff" || role === "manager" || role === "admin") && (
        <>
          <Link to="/appointments" style={linkStyle}>Appointments</Link>

          {(role === "manager" || role === "admin") && (
            <Link to="/vehicles/add" style={linkStyle}>Add Vehicle</Link>
          )}

          {role === "admin" && (
            <Link to="/admin/create-staff" style={linkStyle}>Create Staff</Link>
          )}

          <button onClick={logout} style={{ padding: "6px 10px", cursor: "pointer" }}>
            Logout
          </button>
        </>
      )}

      {/* Fallback if role missing */}
      {isLogged && !role && (
        <>
          <button onClick={logout} style={{ padding: "6px 10px", cursor: "pointer" }}>
            Logout
          </button>
        </>
      )}
    </nav>
  );
}
